import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Chip,
  Divider,
  IconButton,
  Stack,
  Container,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  CircularProgress,
  Alert,
  Snackbar
} from '@mui/material';
import { Add, Delete, Save } from '@mui/icons-material';
import { useFirebase } from '../../context/FirebaseContext';
import { CarSpecifications, Raffle, CarFeature } from '../../types';

interface CarSpecificationsFormProps {
  raffle: Raffle;
  onCancel: () => void;
  onSaved: () => void;
}

const initialSpecsState: CarSpecifications = {
  make: '',
  model: '',
  year: new Date().getFullYear(),
  engine: {
    type: '',
    displacement: '',
    horsepower: 0,
    torque: ''
  },
  transmission: '',
  drivetrain: '',
  acceleration: '',
  topSpeed: '',
  power: '',
  fuel: '',
  features: [],
  exteriorColor: '',
  interiorColor: '',
  dimensions: {
    length: '',
    width: '',
    height: '',
    wheelbase: ''
  },
  weight: '',
  fuelEconomy: ''
};

const CarSpecificationsForm: React.FC<CarSpecificationsFormProps> = ({ raffle, onCancel, onSaved }) => {
  const { updateCarSpecs, getAllCarFeatures, carFeatures } = useFirebase();
  const [specs, setSpecs] = useState<CarSpecifications>(
    raffle.carSpecifications || initialSpecsState
  );
  const [newFeature, setNewFeature] = useState('');
  const [selectedFeature, setSelectedFeature] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);
  const [availableFeatures, setAvailableFeatures] = useState<CarFeature[]>([]);

  // Загрузка доступных особенностей автомобиля
  useEffect(() => {
    const loadFeatures = async () => {
      try {
        // Используем особенности из контекста, если они уже загружены
        if (carFeatures && carFeatures.length > 0) {
          setAvailableFeatures(carFeatures);
        } else {
          // Иначе загружаем из базы данных
          const features = await getAllCarFeatures();
          setAvailableFeatures(features);
        }
      } catch (err) {
        console.error('Ошибка при загрузке особенностей автомобиля:', err);
        setError('Не удалось загрузить особенности автомобиля');
      }
    };

    loadFeatures();
  }, [getAllCarFeatures, carFeatures]);

  // Обработчик изменения текстовых полей
  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setSpecs(prev => {
        const parentObj = prev[parent as keyof CarSpecifications];
        if (parentObj && typeof parentObj === 'object') {
          return {
            ...prev,
            [parent]: {
              ...parentObj,
              [child]: value
            }
          };
        }
        return prev;
      });
    } else {
      setSpecs(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };
  
  // Обработчик изменения числовых полей
  const handleNumberChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setSpecs(prev => {
        const parentObj = prev[parent as keyof CarSpecifications];
        if (parentObj && typeof parentObj === 'object') {
          return {
            ...prev,
            [parent]: {
              ...parentObj,
              [child]: value ? Number(value) : 0
            }
          };
        }
        return prev;
      });
    } else {
      setSpecs(prev => ({
        ...prev,
        [name]: value ? Number(value) : 0
      }));
    }
  };
  
  // Обработчик добавления особенности вручную
  const handleAddFeature = () => {
    if (newFeature.trim()) {
      if (!specs.features.includes(newFeature.trim())) {
        setSpecs(prev => ({
          ...prev,
          features: [...prev.features, newFeature.trim()]
        }));
      }
      setNewFeature('');
    }
  };
  
  // Обработчик добавления особенности из списка
  const handleAddSelectedFeature = () => {
    if (selectedFeature) {
      const feature = availableFeatures.find(f => f.id === selectedFeature);
      if (feature && !specs.features.includes(feature.name)) {
        setSpecs(prev => ({
          ...prev,
          features: [...prev.features, feature.name]
        }));
      }
      setSelectedFeature('');
    }
  };
  
  // Обработчик удаления особенности
  const handleDeleteFeature = (index: number) => {
    setSpecs(prev => ({
      ...prev,
      features: prev.features.filter((_, i) => i !== index)
    }));
  };
  
  // Обработчик сохранения спецификаций
  const handleSave = async () => {
    try {
      setLoading(true);
      setError(null);
      
      // Обновление мощности, если она не указана явно
      if (!specs.power && specs.engine.horsepower) {
        specs.power = `${specs.engine.horsepower} л.с.`;
      }
      
      await updateCarSpecs(raffle.id, specs);
      setSuccess(true);
      
      // Вызов колбека успешного сохранения
      setTimeout(() => {
        onSaved();
      }, 1500);
    } catch (err) {
      console.error('Ошибка при сохранении спецификаций:', err);
      setError('Ошибка при сохранении спецификаций автомобиля');
    } finally {
      setLoading(false);
    }
  };
  
  // Обработчик закрытия уведомления об успешном сохранении
  const handleCloseSuccess = () => {
    setSuccess(false);
  };
  
  return (
    <Paper sx={{ p: 3, borderRadius: 2, mb: 4 }}>
      <Typography variant="h5" component="h2" gutterBottom>
        Спецификации автомобиля
      </Typography>
      <Divider sx={{ mb: 3 }} />
      
      {error && (
        <Alert severity="error" sx={{ mb: 3 }}>
          {error}
        </Alert>
      )}
      
      <Box sx={{ flexGrow: 1 }}>
        <Stack spacing={3}>
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
            <Box sx={{ flex: '1 1 45%', minWidth: '250px' }}>
              <TextField
                fullWidth
                label="Марка"
                name="make"
                value={specs.make}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 45%', minWidth: '250px' }}>
              <TextField
                fullWidth
                label="Модель"
                name="model"
                value={specs.model}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
          </Box>
          
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
            <Box sx={{ flex: '1 1 30%', minWidth: '200px' }}>
              <TextField
                fullWidth
                label="Год выпуска"
                name="year"
                type="number"
                value={specs.year}
                onChange={handleNumberChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 30%', minWidth: '200px' }}>
              <TextField
                fullWidth
                label="Цвет кузова"
                name="exteriorColor"
                value={specs.exteriorColor}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 30%', minWidth: '200px' }}>
              <TextField
                fullWidth
                label="Цвет салона"
                name="interiorColor"
                value={specs.interiorColor}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
          </Box>
          
          <Box sx={{ width: '100%', mt: 2 }}>
            <Typography variant="h6" gutterBottom>
              Двигатель
            </Typography>
            <Divider sx={{ mb: 2 }} />
          </Box>
          
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
            <Box sx={{ flex: '1 1 23%', minWidth: '200px' }}>
              <TextField
                fullWidth
                label="Тип двигателя"
                name="engine.type"
                value={specs.engine.type}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 23%', minWidth: '200px' }}>
              <TextField
                fullWidth
                label="Объем (л)"
                name="engine.displacement"
                value={specs.engine.displacement}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 23%', minWidth: '200px' }}>
              <TextField
                fullWidth
                label="Мощность (л.с.)"
                name="engine.horsepower"
                type="number"
                value={specs.engine.horsepower}
                onChange={handleNumberChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 23%', minWidth: '200px' }}>
              <TextField
                fullWidth
                label="Крутящий момент"
                name="engine.torque"
                value={specs.engine.torque}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
          </Box>
          
          <Box sx={{ width: '100%', mt: 2 }}>
            <Typography variant="h6" gutterBottom>
              Трансмиссия и динамика
            </Typography>
            <Divider sx={{ mb: 2 }} />
          </Box>
          
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
            <Box sx={{ flex: '1 1 30%', minWidth: '200px' }}>
              <TextField
                fullWidth
                label="Коробка передач"
                name="transmission"
                value={specs.transmission}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 23%', minWidth: '200px' }}>
              <TextField
                fullWidth
                label="Привод"
                name="drivetrain"
                value={specs.drivetrain}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 23%', minWidth: '200px' }}>
              <TextField
                fullWidth
                label="Разгон 0-100 км/ч"
                name="acceleration"
                value={specs.acceleration}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 15%', minWidth: '150px' }}>
              <TextField
                fullWidth
                label="Макс. скорость"
                name="topSpeed"
                value={specs.topSpeed}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
          </Box>
          
          <Box sx={{ width: '100%', mt: 2 }}>
            <Typography variant="h6" gutterBottom>
              Размеры и вес
            </Typography>
            <Divider sx={{ mb: 2 }} />
          </Box>
          
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
            <Box sx={{ flex: '1 1 23%', minWidth: '150px' }}>
              <TextField
                fullWidth
                label="Длина (мм)"
                name="dimensions.length"
                value={specs.dimensions.length}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 23%', minWidth: '150px' }}>
              <TextField
                fullWidth
                label="Ширина (мм)"
                name="dimensions.width"
                value={specs.dimensions.width}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 23%', minWidth: '150px' }}>
              <TextField
                fullWidth
                label="Высота (мм)"
                name="dimensions.height"
                value={specs.dimensions.height}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 23%', minWidth: '150px' }}>
              <TextField
                fullWidth
                label="Колесная база (мм)"
                name="dimensions.wheelbase"
                value={specs.dimensions.wheelbase}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
          </Box>
          
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
            <Box sx={{ flex: '1 1 48%', minWidth: '250px' }}>
              <TextField
                fullWidth
                label="Вес (кг)"
                name="weight"
                value={specs.weight}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
            <Box sx={{ flex: '1 1 48%', minWidth: '250px' }}>
              <TextField
                fullWidth
                label="Расход топлива"
                name="fuelEconomy"
                value={specs.fuelEconomy}
                onChange={handleChange}
                variant="outlined"
                margin="normal"
              />
            </Box>
          </Box>
          
          <Box sx={{ width: '100%', mt: 2 }}>
            <Typography variant="h6" gutterBottom>
              Комплектация и особенности
            </Typography>
            <Divider sx={{ mb: 2 }} />
          </Box>
          
          <Box>
            <Typography variant="subtitle1" gutterBottom>
              Добавить из существующих особенностей:
            </Typography>
            <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
              <FormControl fullWidth sx={{ mr: 1 }}>
                <InputLabel id="feature-select-label">Особенность</InputLabel>
                <Select
                  labelId="feature-select-label"
                  id="feature-select"
                  value={selectedFeature}
                  label="Особенность"
                  onChange={(e) => setSelectedFeature(e.target.value)}
                >
                  {availableFeatures.map((feature) => (
                    <MenuItem key={feature.id} value={feature.id}>
                      {feature.name} ({feature.category})
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
              <IconButton 
                color="primary" 
                onClick={handleAddSelectedFeature}
                disabled={!selectedFeature}
              >
                <Add />
              </IconButton>
            </Box>
            
            <Typography variant="subtitle1" gutterBottom>
              Добавить новую особенность:
            </Typography>
            <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
              <TextField
                fullWidth
                label="Новая особенность"
                value={newFeature}
                onChange={(e) => setNewFeature(e.target.value)}
                variant="outlined"
                onKeyPress={(e) => e.key === 'Enter' && handleAddFeature()}
              />
              <IconButton 
                color="primary" 
                onClick={handleAddFeature}
                sx={{ ml: 1 }}
                disabled={!newFeature.trim()}
              >
                <Add />
              </IconButton>
            </Box>
            
            <Typography variant="subtitle1" gutterBottom>
              Текущие особенности:
            </Typography>
            <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
              {specs.features.length > 0 ? (
                specs.features.map((feature, index) => (
                  <Chip
                    key={index}
                    label={feature}
                    onDelete={() => handleDeleteFeature(index)}
                    color="primary"
                    variant="outlined"
                    sx={{ m: 0.5 }}
                  />
                ))
              ) : (
                <Typography variant="body2" color="text.secondary">
                  Нет добавленных особенностей
                </Typography>
              )}
            </Box>
          </Box>
          
          <Box sx={{ display: 'flex', justifyContent: 'flex-end', mt: 3 }}>
            <Button 
              variant="outlined" 
              onClick={onCancel}
              sx={{ mr: 2 }}
              disabled={loading}
            >
              Отмена
            </Button>
            <Button 
              variant="contained"
              color="primary"
              onClick={handleSave}
              disabled={loading}
              startIcon={loading ? <CircularProgress size={20} /> : <Save />}
            >
              {loading ? 'Сохранение...' : 'Сохранить'}
            </Button>
          </Box>
        </Stack>
      </Box>
      
      <Snackbar
        open={success}
        autoHideDuration={3000}
        onClose={handleCloseSuccess}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      >
        <Alert onClose={handleCloseSuccess} severity="success" sx={{ width: '100%' }}>
          Спецификации успешно сохранены!
        </Alert>
      </Snackbar>
    </Paper>
  );
};

export default CarSpecificationsForm;
